#include <stdio.h>
int arr[1000];
int top[1000];
int next[1000];
int free;

void init(int N, int S) {
    for (int i = 0; i < S - 1; i++) {
        next[i] = i + 1;
    }
    next[S - 1] = -1;
    free = 0;
    for (int i = 0; i < N; i++) {
        top[i] = -1;
    }
}

int push(int X, int M) {
    if (free == -1) return 0;
    int i = free;
    free = next[i];
    arr[i] = X;
    next[i] = top[M - 1];
    top[M - 1] = i;
    return 1;
}

int pop(int M) {
    if (top[M - 1] == -1) return -1;
    int i = top[M - 1];
    top[M - 1] = next[i];
    next[i] = free;
    free = i;
    return arr[i];
}

int main() {
    int N, S, Q;
    scanf("%d %d %d", &N, &S, &Q);
    init(N, S);
    while (Q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int X, M;
            scanf("%d %d", &X, &M);
            printf("%d\n", push(X, M));
        } else {
            int M;
            scanf("%d", &M);
            printf("%d\n", pop(M));
        }
    }
    return 0;
}

