import java.util.Scanner;
public class Main {
    static int[] arr = new int[1000];
    static int[] top = new int[1000];
    static int[] next = new int[1000];
    static int free;

    public static void init(int N, int S) {
        for (int i = 0; i < S - 1; i++) {
            next[i] = i + 1;
        }
        next[S - 1] = -1;
        free = 0;
        for (int i = 0; i < N; i++) {
            top[i] = -1;
        }
    }

    public static int push(int X, int M) {
        if (free == -1) return 0;
        int i = free;
        free = next[i];
        arr[i] = X;
        next[i] = top[M - 1];
        top[M - 1] = i;
        return 1;
    }

    public static int pop(int M) {
        if (top[M - 1] == -1) return -1;
        int i = top[M - 1];
        top[M - 1] = next[i];
        next[i] = free;
        free = i;
        return arr[i];
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int S = sc.nextInt();
        int Q = sc.nextInt();
        init(N, S);
        while (Q-- > 0) {
            int type = sc.nextInt();
            if (type == 1) {
                int X = sc.nextInt();
                int M = sc.nextInt();
                System.out.println(push(X, M) == 1 ? "True" : "False");
            } else {
                int M = sc.nextInt();
                System.out.println(pop(M));
            }
        }
    }
}

